diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index c06d5c759634..7773be33391c 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3130,7 +3130,73 @@ Value *InstCombinerImpl::foldAndOrOfICmps(ICmpInst *LHS, ICmpInst *RHS,
     return Builder.CreateICmp(PredL, NewAnd,
                               Constant::getAllOnesValue(LHS0->getType()));
   }
-
+  // (X != -1) && (X+1 <= Y) --> X < Y
+  // (X != -1) && (X+1 < Y) --> X < Y-1? TODO
+  // (X != -1) && (X+1 <= Y) --> X < Y
+  // (X != -1) && (X+1 < Y) --> X < Y-1? TODO
+  if (!IsLogical) {
+    ICmpInst::Predicate EqPred = IsAnd ? ICmpInst::ICMP_NE : ICmpInst::ICMP_EQ;
+    Value *X = nullptr, *Y = nullptr;
+    Constant *C = nullptr, *D = nullptr;
+    ICmpInst::Predicate UnsPred = ICmpInst::BAD_ICMP_PREDICATE;
+    // Determine which icmp is equality with constant
+    if (PredL == EqPred && match(LHS1, m_Constant(C))) {
+      X = LHS0;
+      UnsPred = PredR;
+      if (!ICmpInst::isUnsigned(UnsPred))
+        return nullptr;
+      // Match other icmp: X + D compared to Y, with D = -C
+      Value *Op0 = RHS0, *Op1 = RHS1;
+      if (match(Op0, m_Add(m_Specific(X), m_Constant(D))) &&
+          ConstantExpr::getAdd(C, D)->isNullValue()) {
+        Y = Op1;
+      } else if (match(Op1, m_Add(m_Specific(X), m_Constant(D))) &&
+                 ConstantExpr::getAdd(C, D)->isNullValue()) {
+        Y = Op0;
+      } else {
+        return nullptr;
+      }
+    } else if (PredR == EqPred && match(RHS1, m_Constant(C))) {
+      X = RHS0;
+      UnsPred = PredL;
+      if (!ICmpInst::isUnsigned(UnsPred))
+        return nullptr;
+      Value *Op0 = LHS0, *Op1 = LHS1;
+      if (match(Op0, m_Add(m_Specific(X), m_Constant(D))) &&
+          ConstantExpr::getAdd(C, D)->isNullValue()) {
+        Y = Op1;
+      } else if (match(Op1, m_Add(m_Specific(X), m_Constant(D))) &&
+                 ConstantExpr::getAdd(C, D)->isNullValue()) {
+        Y = Op0;
+      } else {
+        return nullptr;
+      }
+    } else {
+      return nullptr;
+    }
+    // Now we have X, Y, C, D, UnsPred.
+    // Map UnsPred to new predicate.
+    ICmpInst::Predicate NewPred = ICmpInst::BAD_ICMP_PREDICATE;
+    switch (UnsPred) {
+    case ICmpInst::ICMP_ULE: NewPred = ICmpInst::ICMP_ULT; break;
+    case ICmpInst::ICMP_ULT: NewPred = ICmpInst::ICMP_ULE; break;
+    case ICmpInst::ICMP_UGE: NewPred = ICmpInst::ICMP_UGT; break;
+    case ICmpInst::ICMP_UGT: NewPred = ICmpInst::ICMP_UGE; break;
+    default: return nullptr;
+    }
+    // Compute X + (D - 1)
+    Constant *One = ConstantInt::get(X->getType(), 1);
+    Constant *NewD = ConstantExpr::getAdd(D, ConstantExpr::getNeg(One)); // D - 1
+    Value *NewAdd = NewD->isNullValue() ? X : Builder.CreateAdd(X, NewD);
+    // Determine ordering: original comparison was (X + D) Pred Y.
+    // After offset, we need NewAdd NewPred Y.
+    // However, if UnsPred is UGE or UGT, the original ordering may have Y as first operand?
+    // Actually we already captured Y as the other operand (not the add).
+    // So the comparison is (X + D) Pred Y (or Y Pred X + D). We have normalized Y as the other operand.
+    // The predicate already encodes the direction.
+    // Thus we can directly create NewAdd NewPred Y.
+    return Builder.CreateICmp(NewPred, NewAdd, Y);
+  }
   // This only handles icmp of constants: (icmp1 A, C1) | (icmp2 B, C2).
   if (!LHSC || !RHSC)
     return nullptr;

