  3211 |   // share same sign. An example of the pattern:
  3212 |   // (icmp slt (X & Y), 0) | (icmp sgt (X | Y), -1) -> (icmp sgt (X ^ Y), -1)
  3213 |   // Inverted form (example):
  3214 |   // (icmp slt (X | Y), 0) & (icmp sgt (X & Y), -1) -> (icmp slt (X ^ Y), 0)
  3215 |   bool TrueIfSignedL, TrueIfSignedR;
  3216 |   if (isSignBitCheck(PredL, *LHSC, TrueIfSignedL) &&
  3217 |       isSignBitCheck(PredR, *RHSC, TrueIfSignedR) &&
  3218 |       (RHS->hasOneUse() || LHS->hasOneUse())) {
  3219 |     Value *X, *Y;
  3220 |     if (IsAnd) {
