  3222 |            match(LHS0, m_Or(m_Value(X), m_Value(Y))) &&
  3223 |            match(RHS0, m_c_And(m_Specific(X), m_Specific(Y)))) ||
  3224 |           (!TrueIfSignedL && TrueIfSignedR &&
  3225 |            match(LHS0, m_And(m_Value(X), m_Value(Y))) &&
  3226 |            match(RHS0, m_c_Or(m_Specific(X), m_Specific(Y))))) {
