  3236 |            match(RHS0, m_c_And(m_Specific(X), m_Specific(Y))))) {
  3237 |         Value *NewXor = Builder.CreateXor(X, Y);
  3238 |         return Builder.CreateIsNotNeg(NewXor);
  3239 |       }
  3240 |     }
  3241 |   }
  3242 | 
  3243 |   return foldAndOrOfICmpsUsingRanges(LHS, RHS, IsAnd);
